-- Enable Row Level Security\n\nALTER TABLE your_table_name ENABLE ROW LEVEL SECURITY;\n\n-- Create policies for tenant isolation\n\nCREATE POLICY select_tenant_data ON your_table_name\n    FOR SELECT\n    USING (tenant_id = current_setting('app.current_tenant')::uuid);\n\nCREATE POLICY insert_tenant_data ON your_table_name\n    FOR INSERT\n    WITH CHECK (tenant_id = current_setting('app.current_tenant')::uuid);\n\nCREATE POLICY update_tenant_data ON your_table_name\n    FOR UPDATE\n    USING (tenant_id = current_setting('app.current_tenant')::uuid)\n    WITH CHECK (tenant_id = current_setting('app.current_tenant')::uuid);\n\nCREATE POLICY delete_tenant_data ON your_table_name\n    FOR DELETE\n    USING (tenant_id = current_setting('app.current_tenant')::uuid);\n\n-- Set the current tenant (this should be done per session)\n\nSELECT set_config('app.current_tenant', 'tenant-id-value', false);\n\n-- Replace 'your_table_name' with the actual table name\n-- Replace 'tenant-id-value' with actual tenant ID when establishing a session.